INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-kaya-skin-clinic'), 1, 'Is Uncover cheaper than Kaya?', 'Depends on the treatment. Both clinics package services differently. We recommend a free consultation at each to compare itemised quotes for what you actually need.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-kaya-skin-clinic'), 2, 'Does Kaya have dermatologists?', 'Kaya offers dermatologist consultations. Day-to-day procedures across the network are handled by a mix of doctors and trained therapists depending on the service. Ask your specific Kaya clinic for details.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-kaya-skin-clinic'), 3, 'How many clinics does Uncover have in Delhi?', 'Four in Delhi (GK, Lajpat Nagar, Preet Vihar, Punjabi Bagh), three in Gurgaon, one in Noida. Eight total across Delhi NCR.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-kaya-skin-clinic'), 4, 'Can I switch from Kaya to Uncover mid-treatment?', 'Yes — bring any existing treatment plan and photos, and we''ll do a fresh consultation to build on or adjust the plan.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-kaya-skin-clinic'), 5, 'Which is better for laser hair removal?', 'Both offer laser hair removal. The device and the operator matter more than the brand. Ask which laser they use and who runs your session.');

