VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-oliva-skin-clinic'), 1, 'How does Oliva compare on laser hair removal?', 'Both offer laser hair removal. The device and operator matter more than the brand — ask which laser they use.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-oliva-skin-clinic'), 2, 'Which has better Delhi NCR coverage?', 'Uncover runs 8 Delhi NCR clinics. Check Oliva''s website for their current Delhi NCR locations.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-oliva-skin-clinic'), 3, 'Is Uncover cheaper than Oliva?', 'Varies by treatment. Request itemised quotes from both clinics.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'uncover-vs-oliva-skin-clinic'), 4, 'Can I continue my Oliva plan at Uncover?', 'Yes — bring your treatment history and photos. We''ll do a fresh consultation and either continue or adjust the plan.'),
