INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-kaya-skin-clinic-delhi-ncr'), 1, 'Why look beyond Kaya?', 'Plenty of reasons — proximity, cost, specific treatment needs, preference for dermatologist-led delivery, or just exploring options. Most patients benefit from free consultations at 2–3 clinics before committing.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-kaya-skin-clinic-delhi-ncr'), 2, 'Is Uncover owned by Kaya?', 'No, Uncover is an independent dermatologist-led chain.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-kaya-skin-clinic-delhi-ncr'), 3, 'Who has the best laser hair removal in Delhi?', 'Depends on location, device, and the specific dermatologist. Ask which laser each clinic uses — dermatologist-grade devices (Alma Soprano, Candela GentleMax) are what you''re looking for.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-kaya-skin-clinic-delhi-ncr'), 4, 'Do all these clinics have dermatologists?', 'Dermatologist availability varies across chain clinics. Confirm with the specific branch that a dermatologist will see you — it''s a question worth asking directly.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-kaya-skin-clinic-delhi-ncr'), 5, 'Can I switch mid-treatment?', 'Yes — bring your treatment history and photos to any new clinic. A fresh consultation will either continue or adjust your plan.');

