  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  '5 alternatives to Oliva Skin Clinic in Delhi NCR',
  'alternatives-to-oliva-skin-clinic-delhi-ncr',
  'If you''re comparing Oliva with other skin clinics in Delhi NCR, here are five dermatologist-led options with what each is best at.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Oliva has a reasonable footprint in India for skin and hair services, particularly in the south. In Delhi NCR the options broaden — several dermatologist-led clinics offer similar service ranges. Here are five alternatives worth a free consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1. Uncover", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dermatologist-led chain with 8 Delhi NCR locations (4 Delhi, 3 Gurgaon, 1 Noida). AI skin analysis at every consultation. Strong in laser hair removal, HydraFacial, anti-aging, hair restoration including FUE, and body contouring. Transparent published pricing.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2. Kaya Skin Clinic", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "National chain with a large Delhi NCR presence. Core services overlap with Oliva — laser hair removal, pigmentation, anti-aging. Service mix and dermatologist availability vary by specific branch.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "3. Dermaclinix", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Delhi-based dermatology practice, particularly known for hair restoration. Fits patients preferring doctor-owned single-clinic practices over chain delivery.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "4. Skin & Shape (Dr. Geetika Mittal)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Boutique dermatology clinic with emphasis on aesthetic dermatology. Good fit if you prefer a single high-touch dermatologist experience.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "5. The Skin Story (Dr. Jaishree Sharad)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Senior dermatologist single-clinic practice in Delhi. Especially strong in pigmentation and melasma treatment for Indian skin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Choosing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Core services (laser, HydraFacial, pigmentation) are offered competently across most of these. The decision usually comes down to proximity, who you''re actually seeing for your procedure, and whether you want a chain or a boutique experience. Book free consultations at two or three and pick based on plan quality, not brochure copy.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Oliva Skin Clinic Alternatives in Delhi NCR — 5 Options | Uncover',
  'Five Delhi NCR alternatives to Oliva Skin Clinic. Dermatologist-led chains and specialists with what each offers.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr'), 1, 'Why look beyond Oliva?', 'Typical reasons are proximity, pricing, specific treatment needs, or preference for dermatologist-led delivery across every step.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr'), 2, 'Is Uncover related to Oliva?', 'No — separate, independent chain.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr'), 3, 'Which has the best pigmentation treatment?', 'Pigmentation treatment is highly dermatologist-dependent. The Skin Story (Dr. Jaishree Sharad) is well-known for it. Uncover also offers dermatologist-led pigmentation treatment with Q-switch laser and AI skin analysis.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr'), 4, 'Do all of these have dermatologists?', 'Yes — all five have dermatologists. Delivery model differs (chain vs boutique, doctor-led vs doctor-plus-therapists). Confirm at consultation.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'alternatives-to-oliva-skin-clinic-delhi-ncr'), 5, 'Who''s the best for laser hair removal?', 'Depends on device and operator more than brand. Ask which laser is used — Alma Soprano Titanium or Candela GentleMax Pro are good standards.');

-- ===== doctor-led-vs-chain-salon-why-it-matters =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Doctor-led clinic vs chain salon — why the difference matters',
  'doctor-led-vs-chain-salon-why-it-matters',
  'Most patients lump dermatology clinics and beauty-chain salons together. They''re different categories — here''s what separates them and when each is appropriate.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A lot of patients come to us after a bad experience at a beauty chain — usually a pigmentation mark from aggressive extraction, a burn from an under-trained laser operator, or a case of PIH from a peel done at the wrong depth. The confusion between dermatology clinics and beauty salons isn''t the patient''s fault — marketing deliberately blurs it. Here''s what actually separates them.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Who does the procedure", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At a dermatologist-led clinic: MD DVL or DNB dermatologist diagnoses, plans, and supervises every procedure. Many procedures (injections, laser on pigmented skin, deeper peels) are performed by the dermatologist directly. At a chain salon or beauty franchise: a trained therapist or cosmetologist usually performs the procedure. A doctor may be available for consultation but typically doesn''t run the session.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Device quality", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dermatologist-grade lasers (Alma Soprano, Candela GentleMax, Lumenis UltraPulse, Fotona) cost 10–30x what salon IPL costs. The efficacy difference is real — fewer sessions, safer on pigmented skin, better results. Medical-grade microneedling RF, chemical peels, and injectable products also cost significantly more.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Diagnosis ability", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A dermatologist can diagnose melasma vs tan, androgenic vs telogen hair loss, acne vs rosacea, eczema vs fungal — these all look cosmetic but are medical. A cosmetologist legally cannot diagnose. Treating the wrong condition is why some patients get worse over time.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What a salon is actually good for", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Regular facials for maintenance", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Threading and basic waxing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Basic body massages", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Manicures and pedicures", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair cutting and styling", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What needs a dermatologist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Acne (especially if persistent or scarring)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pigmentation (melasma, PIH, sun damage)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair loss (any cause)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Any laser treatment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Any injectable (botox, fillers, GFC, PRP)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Any chemical peel beyond mild home-grade", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 7, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Changes in moles, rashes that persist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 8, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skin conditions with any medical component", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The practical rule", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If it''s aesthetic maintenance with no medical component, a salon is fine. If it''s a medical condition, needs a prescription, or uses medical-grade equipment — it needs a dermatologist. Mixing the two up is where skin damage tends to happen.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Doctor-Led Clinic vs Chain Salon — Why It Matters | Uncover',
  'What separates a dermatologist-led medical clinic from a beauty-chain salon. When each makes sense — and when it doesn''t.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters'), 1, 'Can salons legally do laser?', 'Some lower-powered IPL devices are allowed in salon settings. Medical-grade laser treatment requires a dermatologist.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters'), 2, 'Is a chain salon cheaper?', 'Often yes upfront. The cost of fixing PIH or scarring from an under-trained session usually wipes out the savings.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters'), 3, 'Why does device quality matter?', 'Dermatologist-grade lasers are safer and faster on pigmented Indian skin. Fewer sessions, better results, lower burn risk.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters'), 4, 'Can a salon diagnose acne?', 'No. They can identify visible acne but cannot legally diagnose or prescribe. Persistent or scarring acne needs a dermatologist.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'doctor-led-vs-chain-salon-why-it-matters'), 5, 'What''s the biggest risk at a salon medical procedure?', 'Wrong diagnosis leading to wrong treatment, or wrong-setting procedure causing pigmentation, burns, or scarring. All avoidable with a dermatologist.');

-- ===== best-dermatologist-led-skin-clinic-delhi-ncr =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'The best dermatologist-led skin clinic in Delhi NCR — 7 things to look for',
  'best-dermatologist-led-skin-clinic-delhi-ncr',
  'Delhi NCR has dozens of skin clinics. Only some are actually dermatologist-led at the delivery level. Here''s the 7-point filter to find the best fit.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients in Delhi NCR shortlist skin clinics by proximity and Instagram presence. Neither correlates with quality. Here''s the actual 7-point filter a dermatologist would use.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "1. The lead doctor is a dermatologist (verify it)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "MD DVL or DNB in Dermatology. Verifiable at nmc.org.in. Not ''skin specialist'', not ''cosmetologist'', not ''aesthetician'' — a board-certified dermatologist.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2. The dermatologist does the procedure (not just the consultation)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Plenty of chains have dermatologists for the consultation then hand off to therapists for the procedure. For injectables, lasers on pigmented skin, and chemical peels, the dermatologist should be the one doing it — not just signing off.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "3. Device quality you can look up", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Ask the name of the laser and search for it. Alma Soprano Titanium, Candela GentleMax Pro, Lumenis UltraPulse, Fotona — these are the standards. Generic IPL or no-brand devices are not the same category.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "4. AI skin analysis or equivalent objective tool", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Progress needs to be measured, not just remembered. Standardised imaging or AI skin analysis gives you and the dermatologist an objective baseline. Without it you''re trusting memory.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "5. Transparent pricing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Published starting prices. Itemised plans before you commit. No pressure to sign at the first consultation. Flat refusal of these three is a strong sign the clinic isn''t the right fit.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "6. Honest limits", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A good dermatologist tells you what you can''t achieve, not just what you can. ''Results in one session'', ''permanent in 3 sessions'', ''look 20 years younger'' are sales claims, not medical ones. A clinic that sets honest expectations is worth more than one that promises everything.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "7. Follow-up built into the plan", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "2-week review after any injectable. Photo-based progress checks at 1, 3, and 6 months for any multi-session treatment. Direct line to the clinic between appointments. Clinics that actually care about outcomes build this in.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A note on chain vs boutique", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Neither is automatically better. Chains offer consistency, proximity, and transparent pricing. Boutique single-dermatologist clinics offer more time per visit and often more specialised work. Both can be excellent if they pass the 7 checks above — and neither is a great pick if they fail them.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Best Dermatologist-Led Skin Clinic in Delhi NCR — 7 Checks | Uncover',
  'How to find the best dermatologist-led skin clinic in Delhi NCR. A 7-point checklist for qualifications, equipment, honesty, and follow-up.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr'), 1, 'How do I verify a dermatologist?', 'nmc.org.in lists every registered medical doctor. Search by name or registration number.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr'), 2, 'What makes Uncover different from other clinics?', 'Dermatologist-led delivery at every step, AI skin analysis on every consultation, transparent starting prices, and 8 Delhi NCR locations that keep sessions convenient.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr'), 3, 'Is a single-dermatologist boutique better?', 'Sometimes. For rare conditions or very specialised work, yes. For routine skin, hair, and body treatments, a well-run dermatologist chain gives comparable quality with more convenience.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr'), 4, 'Should I judge by Google reviews?', 'Reviews are one signal — but read them carefully. Pattern of complaints (bookings, cleanliness, pushy sales) matters more than the star rating alone.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'best-dermatologist-led-skin-clinic-delhi-ncr'), 5, 'How many consultations should I book before committing?', 'Two or three. Compare plans, pricing, and how the dermatologist explains your specific issue. The best-fit clinic usually becomes obvious.');

COMMIT;
